class Solution:
    def decodeString(self, s: str) -> str:
        st, cur, k = [], '', 0
        for c in s:
            if c.isdigit():
                k = k * 10 + int(c)
            elif c == '[':
                st.append((cur, k)); cur, k = '', 0
            elif c == ']':
                prev, num = st.pop()
                cur = prev + num * cur
            else:
                cur += c
        return cur

