class Solution {
public:
    string decodeString(string s) {
        stack<pair<string,int>> st;
        string cur; int k = 0;
        for (char c : s) {
            if (isdigit(c)) k = k*10 + (c-'0');
            else if (c == '[') { st.push({cur,k}); cur.clear(); k=0; }
            else if (c == ']') {
                auto [prev, num] = st.top(); st.pop();
                string rep;
                for (int i=0;i<num;i++) rep += cur;
                cur = prev + rep;
            } else cur.push_back(c);
        }
        return cur;
    }
};

