char* decodeString(char* s) {
    char* cur = calloc(10000,1); char* stackStr[100]; int stackK[100], top=0; int k=0;
    for (int i=0;s[i];i++){
        if (s[i]>='0'&&s[i]<='9') k=k*10+(s[i]-'0');
        else if (s[i]=='['){ stackStr[top]=strdup(cur); stackK[top++]=k; cur[0]=0; k=0; }
        else if (s[i]==']'){
            char* prev=stackStr[--top]; int num=stackK[top];
            char rep[10000]={0}; for(int t=0;t<num;t++) strcat(rep,cur);
            strcpy(cur, prev); strcat(cur, rep); free(prev);
        } else { int len=strlen(cur); cur[len]=s[i]; cur[len+1]=0; }
    }
    return cur;
}
